          hideLeftIcon={false}
          onBack={() => {}}
        />
        <ErrorState onRetry={() => {}} />
      </Box>
    );
  }

  const showTransactionsList = isLoading || transactionsData.length > 0;

  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
      <Header
        title="Extrato"
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {}}
      />
      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
        <Box ml="smaller" mr="smaller" mt="smaller" mb="xxxs">
          <CardPoints
            icon="icon-benefits"
            iconInfo="icon-help"
            title="Pontos disponíveis"
            valuePoints={
              isLoading
                ? ''
                : Math.floor(points).toLocaleString('pt-br')
            }
            hideBottom
            isLoading={isLoading}
            onPressIconInfo={() => {}}
          />

          <Text
            type="paragraphXXXL"
            mb="xxxxs"
            mt="xxs"
            color="INTENSE_COLOR_05"
          >
            Lançamentos
          </Text>

          <SeparatorHorizontal
            borderWidth="smaller"
            borderColor="BRAND_COMPLEMENT_02"
            height={1}
            mb="xxxxs"
            width="100%"
          />
          <SearchUsed
            placeholder="Buscar por pontos, tipos de compra etc"
            onChangeText={() => {}}
            value=""
            showIcon={false}
            firstIcon={undefined}
            onPressIn={() => {}}
            numberIcon={undefined}
            secondIcon="icon-filter-settings"
            secondOnPress={() => {}}
            showFilter
          />
        </Box>

        <Box
          ml={isLoading ? 'xs' : 'none'}
          mr={isLoading ? 'xs' : 'none'}
        >
          <Tabs
            items={[
              {
                id: 0,
                title: 'Todos',
                component: (
                  <TransactionsList
                    items={transactionsData}
                    isLoading={isLoading}
                  />
                ),
              },
              {
                id: 1,
                title: 'A expirar',
                component: <></>,
              },
            ]}
            showBackground={false}
            hasScroll={false}
            loadingType="light"
            onChange={() => {}}
            type="options"
            isLoading={isLoading}
          />
          {!showTransactionsList && (
            <EmptyList
              label={
                isEmpty
                  ? 'Para ganhar pontos, use seu cartão Sem Parar Mais ou a Tag.'
                  : 'Não encontramos resultados para sua busca.'
              }
            />
          )}
