    { id: 'screens-extract--loading', name: 'extract-loading' },
    { id: 'screens-extract--error', name: 'extract-error' },
  ];

  for (const s of stories) {
    const url = 'http://localhost:6006/iframe.html?id=' + s.id + '&viewMode=story&globals=phoneFrame:on;phoneDevice:iphone14';
    await page.goto(url, { waitUntil: 'networkidle', timeout: 30000 });
    await page.waitForTimeout(2500);
    await page.screenshot({ path: '.storybook/screenshots/' + s.name + '.png', fullPage: true });
    console.log('Screenshot: ' + s.name);
  }

  await browser.close();
  console.log('Done!');
})().catch(e => { console.error(e.message); process.exit(1); });
