import React from 'react';
import { Animated, FlatList } from 'react-native';

import { useTheme } from 'styled-components/native';

import theme from '../../../styles/theme';

import RoundedLeft from '../../../assets/svg/RoundedLeft';
import RoundedRight from '../../../assets/svg/RoundedRight';
import { Box, TouchBox } from '../../atoms/Box';
import BoxShadow from '../../atoms/Box/shadow';
import Skeleton from '../../atoms/Skeleton/view';
import { SeparatorHorizontal } from '../../atoms/Spacing';
import { Text } from '../../atoms/Text';
import normalize from '../../constants/normalize';
import { PropsView } from './Models';

function ViewTabs({
  items,
  handleOnPressItem,
  itemActive,
  refFlatList,
  scrollX,
  menuLayout,
  onLayoutMenu,
  flatListLayout,
  onLayoutFlatList,
  measures,
  onLayoutItem,
  mt,
  mb,
  ml,
  mr,
  horizontalSpace,
  testID,
  type,
  animatedViewColor,
  bgColorTouchBoxAsType,
  borderRadiusBottomAsTypeInTouchBox,
  borderRadiusTopAsTypeInBoxShadow,
  borderRadiusTopAsTypeInTouchBox,
  borderWidthAsTypeInBoxShadow,
  borderWidthAsTypeInTouchBox,
  calculateCentralPosition,
  colorBoxShadowAsType,
  levelShadow,
  onLayoutAnimatedView,
  textTitleColor,
  textTitleType,
  translateX,
  renderTouchBoxHeight,
  renderTouchBoxPaddingType,
  onScrollDrag,
  hasScroll,
  widthAnimatedView,
  renderLeftAnimatedView,
  loadingType,
  isLoading,
  isSmall,
  shouldRenderDivider,
  renderHeight,
}: PropsView) {
  const { colors, borderRadius, spaces } = useTheme() || theme;

  return (
    <Box
      testID={testID}
      onLayout={onLayoutFlatList}
      width="100%"
      position="relative"
      index={1}
      mt={mt}
      mb={mb}
      ml={ml}
      mr={mr}
    >
      {isLoading ? (
        <Skeleton
          testID="DS-Tabs-Skeleton"
          type={loadingType}
          width={flatListLayout?.width as number}
          height={isSmall ? 44 : 55}
        />
      ) : (
        <Box
          testID="DS-Tabs-Content-Box"
          width="100%"
          index={1}
          position="relative"
        >
          <Box
            testID="DS-Test-onLayoutMenu"
            onLayout={onLayoutMenu}
            width="100%"
            direction={type !== 'options'}
            justify="space-between"
            bgColor={colorBoxShadowAsType()}
            borderRadiusTopLeft={borderRadiusTopAsTypeInBoxShadow()}
            borderRadiusTopRight={borderRadiusTopAsTypeInBoxShadow()}
            borderRadiusBottomLeft={borderRadiusTopAsTypeInBoxShadow()}
            borderRadiusBottomRight={borderRadiusTopAsTypeInBoxShadow()}
          >
            {type === 'options' ? (
              <FlatList
                testID="DS-ExtractTab-FlatList"
                ref={refFlatList}
                horizontal
                bounces={false}
                overScrollMode="never"
                showsHorizontalScrollIndicator={false}
                data={items}
                contentContainerStyle={{ gap: spaces?.margins.standing.xs }}
                onScrollToIndexFailed={(item) => {
                  setTimeout(() => {
                    refFlatList?.current?.scrollToIndex({
                      index: item.index,
                      animated: true,
                    });
                  }, 200);
                }}
                renderItem={({ item, index }) => (
                  <Box
                    key={index.valueOf()}
                    ml={index === 0 ? 'smaller' : 'none'}
                    mr={index === items.length - 1 ? 'smaller' : 'none'}
                  >
                    <TouchBox
                      testID={`DS-Tabs-Click-${index}`}
                      minWidth={normalize(72)}
                      onPress={() => handleOnPressItem(index)}
                      pd="squishSmaller"
                    >
                      <Text
                        align="center"
                        type={textTitleType(index)}
                        numberOfLines={1}
                        color={textTitleColor(index)}
                        maxFontSizeMultiplier={1.2}
                      >
                        {item.title}
                      </Text>
                    </TouchBox>

                    {itemActive === index && (
                      <Box
                        width="100%"
                        align="center"
                        position="absolute"
                        style={{
                          bottom: 0,
                        }}
                        index={999}
                      >
                        <Box
                          width="100%"
                          bw="small"
                          br="pill"
                          borderColor="BRAND_BASE_01"
                        />
                      </Box>
                    )}
                  </Box>
                )}
              />
            ) : (
              items.map((item, index) => (
                <BoxShadow
                  testID={`DS-Test-onLayoutItem-${index}`}
                  key={index.valueOf()}
                  width={`${100 / items.length}%`}
                  type={levelShadow(index)}
                  onLayout={onLayoutItem}
                  bgColor={
                    type !== 'secondary'
                      ? 'transparent'
                      : bgColorTouchBoxAsType(index)
                  }
                  borderRadiusTopLeft={borderRadiusTopAsTypeInBoxShadow()}
                  borderRadiusTopRight={borderRadiusTopAsTypeInBoxShadow()}
                  borderTopWidth={borderWidthAsTypeInBoxShadow()}
                  borderBottomWidth={borderWidthAsTypeInBoxShadow()}
                  borderLeftWidth={borderWidthAsTypeInBoxShadow()}
                  borderRightWidth={borderWidthAsTypeInBoxShadow()}
                  borderColor="transparent"
                >
                  {type === 'default' &&
                    items.length >= 2 &&
                    item.hasNotification && (
                      <Box
                        position="absolute"
                        index={999}
                        style={{ top: 0, right: 0 }}
                        width={normalize(8)}
                        height={normalize(8)}
                        br="circle"
                        mr="smaller"
                        bgColor="EMPHASIS_COLOR_01"
                        testID="DS-Tabs-Notification"
                      />
                    )}

                  <TouchBox
                    onLayout={(event) =>
                      calculateCentralPosition(event.nativeEvent.layout)
                    }
                    testID={`DS-Tabs-Click-${index}`}
                    minHeight={renderTouchBoxHeight()}
                    bgColor={bgColorTouchBoxAsType(index)}
                    onPress={() => handleOnPressItem(index)}
                    borderRadiusTopLeft={borderRadiusTopAsTypeInTouchBox()}
                    borderRadiusTopRight={borderRadiusTopAsTypeInTouchBox()}
                    borderRadiusBottomLeft={borderRadiusBottomAsTypeInTouchBox()}
                    borderRadiusBottomRight={borderRadiusBottomAsTypeInTouchBox()}
                    borderTopWidth={borderWidthAsTypeInTouchBox()}
                    borderBottomWidth={borderWidthAsTypeInTouchBox()}
                    borderLeftWidth={borderWidthAsTypeInTouchBox()}
                    borderRightWidth={borderWidthAsTypeInTouchBox()}
                    borderColor="transparent"
                    width="100%"
                    pd={renderTouchBoxPaddingType()}
                  >
                    {index === 0 && type === 'rounded' && (
                      <Box
                        width="100%"
                        height={normalize(60)}
                        justify="flex-end"
                        align="flex-end"
                        position="absolute"
                      >
                        <RoundedLeft color={colors.INTENSE_COLOR_01} />
                      </Box>
                    )}

                    <Text
                      width="100%"
                      align="center"
                      type={textTitleType(index)}
                      numberOfLines={1}
                      color={textTitleColor(index)}
                      maxFontSizeMultiplier={1.2}
                    >
                      {item.title}
                    </Text>
                  </TouchBox>

                  {index === 1 && type === 'rounded' && (
                    <Box
                      height={normalize(60)}
                      justify="flex-end"
                      position="absolute"
                    >
                      <RoundedRight color={colors.INTENSE_COLOR_01} />
                    </Box>
                  )}
                </BoxShadow>
              ))
            )}
          </Box>
          {shouldRenderDivider() && (
            <Box
              width="100%"
              mr={horizontalSpace ? 'smaller' : 'none'}
              ml={horizontalSpace ? 'smaller' : 'none'}
              style={{ top: type === 'options' ? -1 : 0 }}
              index={0}
            >
              <SeparatorHorizontal
                width="100%"
                height={1}
                bgColor={
                  type !== 'options'
                    ? 'INTENSE_COLOR_02'
                    : 'BRAND_COMPLEMENT_02'
                }
                testID="DS-Tabs-Divider"
              />
            </Box>
          )}
          <Animated.FlatList
            testID="flatlist"
            ref={refFlatList}
            data={items}
            keyExtractor={(item) => String(item.id)}
            horizontal
            showsHorizontalScrollIndicator={false}
            scrollEnabled={hasScroll}
            pagingEnabled={hasScroll}
            onMomentumScrollEnd={onScrollDrag}
            contentContainerStyle={{
              width: (flatListLayout?.width || 0) * items.length,
            }}
            style={{
              marginTop: type === 'wallet' ? -10 : 0,
            }}
            onScroll={Animated.event(
              [{ nativeEvent: { contentOffset: { x: scrollX } } }],
              { useNativeDriver: false },
            )}
            onScrollToIndexFailed={(item) => {
              setTimeout(() => {
                refFlatList?.current?.scrollToIndex({
                  index: item.index,
                  animated: true,
                });
              }, 200);
            }}
            renderItem={({ item, index }) => (
              <Box
                key={index.valueOf()}
                style={{
                  width: flatListLayout?.width,
                  height: renderHeight(index),
                  opacity: index === itemActive ? 1 : 0,
                }}
              >
                {item.component}
              </Box>
            )}
          />

          {measures.length === items.length &&
            type !== 'rounded' &&
            type !== 'selection' &&
            type !== 'options' && (
              <Animated.View
                onLayout={onLayoutAnimatedView}
                style={{
                  height: type !== 'default' ? 2 : 4,
                  left: renderLeftAnimatedView(),
                  width: widthAnimatedView(),
                  backgroundColor: animatedViewColor(),
                  position: 'absolute',
                  top:
                    type === 'secondary' || type === 'default'
                      ? (menuLayout?.height ?? 0) - 2
                      : menuLayout?.height,
                  zIndex: 999,
                  transform: translateX(),
                  marginTop: type === 'default' ? -1 : 0,
                  borderRadius: type === 'secondary' ? borderRadius?.pill : 0,
                  borderTopLeftRadius:
                    type === 'default' ? borderRadius?.small : 0,
                  borderTopRightRadius:
                    type === 'default' ? borderRadius?.small : 0,
                }}
              />
            )}
        </Box>
      )}
    </Box>
  );
}

export default ViewTabs;

