import { RefObject } from 'react';
import {
  NativeSyntheticEvent,
  Animated,
  FlatList,
  LayoutRectangle,
  LayoutChangeEvent,
} from 'react-native';

import {
  PropsPadding,
  PropsBorderWidth,
  PropsShadowTokens,
  PropsSpacesHorizontal,
  PropsSpacesVertical,
  PropsTokensRadiusCore,
} from '../../../../styles/Models';
import { PropsTokenColorsCore } from '../../../../styles/Models/type.colors';
import { PropsTokensTextCore } from '../../../../styles/Models/type.text';

import { typeSkeleton } from '../../../atoms/Skeleton/Models';

export enum ALLOWED_BG_COLORS {
  INTENSE_COLOR_05 = 'INTENSE_COLOR_05',
  BRAND_COMPLEMENT_01 = 'BRAND_COMPLEMENT_01',
}

type typeAllowedBgColors = keyof typeof ALLOWED_BG_COLORS;

export interface PropsLayout {
  width: number;
  height: number;
  x: number;
  y: number;
}

export interface LayoutEvent {
  layout: PropsLayout;
}

interface PropsItem {
  id: number;
  title: string;
  component: JSX.Element;
  hasNotification?: boolean;
}

export interface PropsTabs {
  items: Array<PropsItem>;
  type?:
    | 'default'
    | 'wallet'
    | 'rounded'
    | 'selection'
    | 'secondary'
    | 'options';
  horizontalSpace?: boolean;
  hasContentSize?: boolean;
  bgColor?: typeAllowedBgColors;
  isSmall?: boolean;
  onChange?: (index: number) => void;
  indexDefault?: number;
  showBackground?: boolean;
  showDivider?: boolean;
  hasScroll?: boolean;
  isLoading?: boolean;
  loadingType?: typeSkeleton;
  mt?: PropsSpacesHorizontal;
  mb?: PropsSpacesHorizontal;
  ml?: PropsSpacesVertical;
  mr?: PropsSpacesVertical;
  testID?: string;
  heavyComponent?: boolean;
}

export interface PropsView extends PropsTabs {
  handleOnPressItem: (itemIndex: number) => void;
  itemActive: number;
  refFlatList: RefObject<FlatList>;
  scrollX: Animated.Value;
  menuLayout: PropsLayout | undefined;
  onLayoutMenu: (event: NativeSyntheticEvent<LayoutEvent>) => void;
  flatListLayout: PropsLayout | undefined;
  onLayoutFlatList: (event: NativeSyntheticEvent<LayoutEvent>) => void;
  measures: Array<PropsLayout>;
  onLayoutItem: (event: NativeSyntheticEvent<LayoutEvent>) => void;
  calculateCentralPosition: (layout: LayoutRectangle) => void;
  onLayoutAnimatedView: (event: LayoutChangeEvent) => void;
  translateX: () => {
    translateX: Animated.AnimatedInterpolation;
  }[];
  levelShadow: (index: number) => PropsShadowTokens;
  colorBoxShadowAsType: () => PropsTokenColorsCore;
  bgColorTouchBoxAsType: (index: number) => PropsTokenColorsCore;
  borderWidthAsTypeInTouchBox: () => PropsBorderWidth;
  borderWidthAsTypeInBoxShadow: () => PropsBorderWidth;
  borderRadiusTopAsTypeInBoxShadow: () => PropsTokensRadiusCore;
  borderRadiusTopAsTypeInTouchBox: () => PropsTokensRadiusCore;
  borderRadiusBottomAsTypeInTouchBox: () => PropsTokensRadiusCore;
  textTitleType: (index: number) => PropsTokensTextCore;
  textTitleColor: (index: number) => PropsTokenColorsCore;
  renderTouchBoxHeight: () => number | 'auto';
  renderTouchBoxPaddingType: () => PropsPadding;
  animatedViewColor: () => void;
  widthAnimatedView: () => string;
  renderLeftAnimatedView: () => number;
  onScrollDrag: (event: PropsNativeEvent) => void;
  shouldRenderDivider: () => boolean;
  renderHeight: (index: number) => 0 | 'auto' | '100%';
}

export interface PropsNativeEvent {
  nativeEvent: {
    contentOffset: {
      x: number;
      y: number;
    };
  };
}

